#[gpui::test]
async fn test_addition_reverts(cx: &mut TestAppContext) {
    init_test(cx, |_| {});
    let mut cx = EditorLspTestContext::new_rust(lsp::ServerCapabilities::default(), cx).await;
    let base_text = indoc! {r#"
        struct Row;
        struct Row1;
        struct Row2;

        struct Row4;
        struct Row5;
        struct Row6;

        struct Row8;
        struct Row9;
        struct Row10;"#};

    // When addition hunks are not adjacent to carets, no hunk revert is performed
    assert_hunk_revert(
        indoc! {r#"struct Row;
                   struct Row1;
                   struct Row1.1;
                   struct Row1.2;
                   struct Row2;Ė

                   struct Row4;
                   struct Row5;
                   struct Row6;

                   struct Row8;
                   Ėstruct Row9;
                   struct Row9.1;
                   struct Row9.2;
                   struct Row9.3;
                   struct Row10;"#},
        vec![DiffHunkStatusKind::Added, DiffHunkStatusKind::Added],
        indoc! {r#"struct Row;
                   struct Row1;
                   struct Row1.1;
                   struct Row1.2;
                   struct Row2;Ė

                   struct Row4;
                   struct Row5;
                   struct Row6;

                   struct Row8;
                   Ėstruct Row9;
                   struct Row9.1;
                   struct Row9.2;
                   struct Row9.3;
                   struct Row10;"#},
        base_text,
        &mut cx,
    );
    // Same for selections
    assert_hunk_revert(
        indoc! {r#"struct Row;
                   struct Row1;
                   struct Row2;
                   struct Row2.1;
                   struct Row2.2;
                   Ā«Ė
                   struct Row4;
                   structĀ» Row5;
                   Ā«struct Row6;
                   ĖĀ»
                   struct Row9.1;
                   struct Row9.2;
                   struct Row9.3;
                   struct Row8;
                   struct Row9;
                   struct Row10;"#},
        vec![DiffHunkStatusKind::Added, DiffHunkStatusKind::Added],
        indoc! {r#"struct Row;
                   struct Row1;
                   struct Row2;
                   struct Row2.1;
                   struct Row2.2;
                   Ā«Ė
                   struct Row4;
                   structĀ» Row5;
                   Ā«struct Row6;
                   ĖĀ»
                   struct Row9.1;
                   struct Row9.2;
                   struct Row9.3;
                   struct Row8;
                   struct Row9;
                   struct Row10;"#},
        base_text,
        &mut cx,
    );

    // When carets and selections intersect the addition hunks, those are reverted.
    // Adjacent carets got merged.
    assert_hunk_revert(
        indoc! {r#"struct Row;
                   Ė// something on the top
                   struct Row1;
                   struct Row2;
                   struct RoĖw3.1;
                   struct Row2.2;
                   struct Row2.3;Ė

                   struct Row4;
                   struct ĖRow5.1;
                   struct Row5.2;
                   struct Ā«RowĖĀ»5.3;
                   struct Row5;
                   struct Row6;
                   Ė
                   struct Row9.1;
                   struct Ā«RowĖĀ»9.2;
                   struct Ā«ĖRowĀ»9.3;
                   struct Row8;
                   struct Row9;
                   Ā«Ė// something on bottomĀ»
                   struct Row10;"#},
        vec![
            DiffHunkStatusKind::Added,
            DiffHunkStatusKind::Added,
            DiffHunkStatusKind::Added,
            DiffHunkStatusKind::Added,
            DiffHunkStatusKind::Added,
        ],
        indoc! {r#"struct Row;
                   Ėstruct Row1;
                   struct Row2;
                   Ė
                   struct Row4;
                   Ėstruct Row5;
                   struct Row6;
                   Ė
                   Ėstruct Row8;
                   struct Row9;
                   Ėstruct Row10;"#},
        base_text,
        &mut cx,
    );
}

